-- Alex_C.T modular Profilarr v4 PCD operations.
-- 04: Video, HDR, and resolution regexes, custom formats, conditions, and bindings.
-- Requires 01.

INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('Video: 10-bit SDR / Main 10 Fallback', '(?i)^(?=.*\b(?:x265|h[ ._-]?265|hevc|av1|x266|h[ ._-]?266|vvc)\b)(?=.*\b(?:10[ ._-]?bit|10b|main[ ._-]?10|yuv420p10le)\b)(?!.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision)).*$', 'Fallback visual-quality bonus for efficient-codec releases that explicitly advertise 10-bit/Main 10 but do not advertise HDR, HDR10, HDR10+, DoVi, DV, or Dolby Vision. This lets 10-bit SDR sit above plain 8-bit HEVC/x265 while staying below true HDR/Dolby Vision.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Video: 10-bit SDR / Main 10 Fallback', 'Codec');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Video: 10-bit SDR / Main 10 Fallback', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('Video: 10-bit SDR / Main 10 Fallback', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: Base HDR Bonus', '(?i)(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+)', 'Base HDR bonus. Keeps HDR above SDR, while still letting the more specific Dolby Vision plus HDR and HDR10+ combinations rise higher.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Base HDR Bonus', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Base HDR Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: HDR10 Bonus', '(?i)\bhdr10\b(?!\+)', 'Extra HDR score for HDR10. This sits above generic HDR but below Dolby Vision paired with HDR and below HDR10+.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: HDR10 Bonus', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: HDR10 Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: HDR10+ Bonus', '(?i)(?:\bhdr10plus\b|\bhdr10\+)', 'Top non-Dolby-Vision HDR bonus for HDR10+ and HDR10 Plus tags. Combined with Dolby Vision, this becomes the strongest HDR path.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: HDR10+ Bonus', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: HDR10+ Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: Dolby Vision Bonus', '(?i)\b(?:dolby[ ._-]?vision|dovi|dv)\b', 'Standalone Dolby Vision signal for movie scoring. Lets profiles reward Dolby Vision directly without bundling it together with HDR or surround requirements.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Dolby Vision Bonus', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Dolby Vision Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: Dolby Vision + HDR Bonus', '(?i)^(?=.*\b(?:dovi|dolby[ ._-]?vision|dv)\b)(?=.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+)).*$', 'Rewards Dolby Vision only when HDR, HDR10, or HDR10+ is also present. This builds the preferred Dolby Vision plus HDR ladders without overvaluing DV-only releases.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Dolby Vision + HDR Bonus', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Dolby Vision + HDR Bonus', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: Penalize SDR When HDR Expected', '(?i)^(?=.*\b(?:1080p|2160p|4k|uhd)\b)(?=.*\b(?:x265|h[ ._-]?265|hevc|av1|x266|h[ ._-]?266|vvc)\b)(?!.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision|\b(?:10[ ._-]?bit|10b|main[ ._-]?10|yuv420p10le)\b)).*$', 'Optional strict detector for efficient-codec 1080p/2160p releases that advertise neither HDR/Dolby Vision nor explicit 10-bit/Main 10. Explicit 10-bit SDR is handled by the Video: 10-bit SDR / Main 10 Fallback custom format.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Penalize SDR When HDR Expected', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('HDR: Dolby Vision Only Fallback', '(?i)^(?=.*\b(?:dovi|dolby[ ._-]?vision|dv)\b)(?!.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+)).*$', 'Small Dolby Vision-only fallback score. DV-only releases stay above SDR when necessary, but below every Dolby Vision plus HDR combination.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Dolby Vision Only Fallback', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('HDR: Dolby Vision Only Fallback', 'Scoring');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K Gate: Block Missing HDR', '(?i)^(?=.*\b(?:2160p|4k)\b)(?!.*(?:\bhdr\b|\bhdr10\b|\bhdr10plus\b|\bhdr10\+|\bdovi\b|\bdv\b|dolby[ ._-]?vision|\b(?:10[ ._-]?bit|10b|main[ ._-]?10|yuv420p10le)\b)).*$', 'Optional strict detector for 2160p/4K releases that advertise neither HDR/Dolby Vision nor explicit 10-bit/Main 10. It preserves HDR-first behavior only when a stricter profile chooses to attach it.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Gate: Block Missing HDR', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K Gate: Block Missing HDR', 'Blocking');
INSERT OR REPLACE INTO regular_expressions (name, pattern, description) VALUES ('4K: Block x264-H264', '(?i)^(?=.*\b(?:2160p|4k)\b)(?=.*\b(?:avc|[xh][ ._-]?264)\b).*$', 'Optional strict detector for 4K or 2160p releases encoded as x264, H.264, or AVC. The default additive profiles leave it unattached and instead let HEVC, AV1, or VVC win through positive bonuses.');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: Block x264-H264', 'HDR / 4K');
INSERT OR REPLACE INTO regular_expression_tags (regular_expression_name, tag_name) VALUES ('4K: Block x264-H264', 'Blocking');
